INSERT INTO shopjoy_2604.sy_bbs (bbs_id, site_id, bbm_id, author_nm, bbs_title, content_html, view_count, like_count, comment_count, is_fixed, bbs_status_cd, reg_by, reg_date) VALUES ('BSFQ000001', 'SITE000001', 'BM000002', 'SYSTEM', '주문 후 배송까지 얼마나 걸리나요?', '결제 확인 후 1~2 영업일 이내 출고됩니다. 출고 후 일반 배송은 2~3일, 제주·도서산간 지역은 추가 2~3일이 소요됩니다.', 0, 0, 0, 'N', 'PUBLISH', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
INSERT INTO shopjoy_2604.sy_bbs (bbs_id, site_id, bbm_id, author_nm, bbs_title, content_html, view_count, like_count, comment_count, is_fixed, bbs_status_cd, reg_by, reg_date) VALUES ('BSFQ000002', 'SITE000001', 'BM000002', 'SYSTEM', '교환·반품은 어떻게 신청하나요?', '상품 수령 후 7일 이내에 고객센터로 연락해주세요. 단, 착용 후 세탁하거나 태그를 제거한 경우 교환·반품이 불가합니다.', 0, 0, 0, 'N', 'PUBLISH', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
INSERT INTO shopjoy_2604.sy_bbs (bbs_id, site_id, bbm_id, author_nm, bbs_title, content_html, view_count, like_count, comment_count, is_fixed, bbs_status_cd, reg_by, reg_date) VALUES ('BSFQ000003', 'SITE000001', 'BM000002', 'SYSTEM', '사이즈 교환이 가능한가요?', '미착용·미세탁 상태에서 7일 이내라면 사이즈 교환이 가능합니다. 왕복 배송비는 고객 부담이며, 재고 상황에 따라 불가한 경우도 있습니다.', 0, 0, 0, 'N', 'PUBLISH', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
INSERT INTO shopjoy_2604.sy_bbs (bbs_id, site_id, bbm_id, author_nm, bbs_title, content_html, view_count, like_count, comment_count, is_fixed, bbs_status_cd, reg_by, reg_date) VALUES ('BSFQ000004', 'SITE000001', 'BM000002', 'SYSTEM', '색상이 화면과 다를 수 있나요?', '모니터 환경에 따라 실제 색상과 다소 차이가 있을 수 있습니다. 정확한 색상은 상품 상세 이미지를 참고하거나 고객센터로 문의해주세요.', 0, 0, 0, 'N', 'PUBLISH', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
INSERT INTO shopjoy_2604.sy_bbs (bbs_id, site_id, bbm_id, author_nm, bbs_title, content_html, view_count, like_count, comment_count, is_fixed, bbs_status_cd, reg_by, reg_date) VALUES ('BSFQ000005', 'SITE000001', 'BM000002', 'SYSTEM', '세탁 방법은 어떻게 되나요?', '각 상품의 라벨에 표기된 세탁 방법을 따라주세요. 대부분의 상품은 찬물 손세탁 또는 세탁기 약세탁을 권장합니다.', 0, 0, 0, 'N', 'PUBLISH', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
INSERT INTO shopjoy_2604.sy_bbs (bbs_id, site_id, bbm_id, author_nm, bbs_title, content_html, view_count, like_count, comment_count, is_fixed, bbs_status_cd, reg_by, reg_date) VALUES ('BSFQ000006', 'SITE000001', 'BM000002', 'SYSTEM', '결제는 어떤 방식으로 하나요?', '현재 계좌이체 방식으로 운영됩니다. 주문 후 안내된 계좌로 입금해주시면 확인 후 발송합니다.', 0, 0, 0, 'N', 'PUBLISH', 'SYSTEM', '2026-04-20 00:00:00') ON CONFLICT DO NOTHING;
